import React, { createContext, useContext, useState, useEffect } from 'react';

// ─── Theme palettes ────────────────────────────────────────────────────────────
export const THEMES = {
  dark: {
    bg:          '#0A0C10',
    surface:     '#111318',
    card:        '#181C24',
    border:      '#252A35',
    borderLight: '#2E3545',
    accent:      '#F5A623',
    accentGlow:  'rgba(245,166,35,0.18)',
    accentDim:   '#C47F0F',
    green:       '#2ECC71',
    greenDim:    'rgba(46,204,113,0.15)',
    red:         '#E74C3C',
    redDim:      'rgba(231,76,60,0.15)',
    blue:        '#3498DB',
    blueDim:     'rgba(52,152,219,0.15)',
    purple:      '#9B59B6',
    text:        '#E8ECF4',
    textMid:     '#8A94A8',
    textDim:     '#4A5568',
  },
  light: {
    bg:          '#F4F5F7',
    surface:     '#FFFFFF',
    card:        '#FFFFFF',
    border:      '#E2E5EC',
    borderLight: '#CBD0DB',
    accent:      '#E0920A',
    accentGlow:  'rgba(224,146,10,0.12)',
    accentDim:   '#B57008',
    green:       '#18A34A',
    greenDim:    'rgba(24,163,74,0.12)',
    red:         '#DC2626',
    redDim:      'rgba(220,38,38,0.10)',
    blue:        '#2563EB',
    blueDim:     'rgba(37,99,235,0.10)',
    purple:      '#7C3AED',
    text:        '#111827',
    textMid:     '#6B7280',
    textDim:     '#9CA3AF',
  },
};

const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
  const [mode, setMode] = useState(() => localStorage.getItem('ros_theme') || 'dark');

  const theme = THEMES[mode];

  // Inject CSS variables onto :root whenever mode changes
  useEffect(() => {
    const root = document.documentElement;
    Object.entries(theme).forEach(([key, val]) => {
      // Convert camelCase to --kebab-case
      const cssVar = '--' + key.replace(/([A-Z])/g, '-$1').toLowerCase();
      root.style.setProperty(cssVar, val);
    });
    // Also set body background directly so there's no flash
    document.body.style.background = theme.bg;
    document.body.style.color      = theme.text;
    localStorage.setItem('ros_theme', mode);
  }, [mode, theme]);

  const toggle = () => setMode(m => m === 'dark' ? 'light' : 'dark');

  return (
    <ThemeContext.Provider value={{ mode, theme, toggle }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used within ThemeProvider');
  return ctx;
}
